import{_ as a,o as d,c as e,a2 as l}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"绿电直连 2.0——从企业购电到物理直连","description":"","frontmatter":{"updated":"2026-06-23T00:00:00.000Z","visibility":"public"},"headers":[],"relativePath":"电力新能源/新赛道/_深化_2026-06-16_绿电直连2.0与绿色燃料.md","filePath":"电力新能源/新赛道/_深化_2026-06-16_绿电直连2.0与绿色燃料.md","lastUpdated":null}'),r={name:"电力新能源/新赛道/_深化_2026-06-16_绿电直连2.0与绿色燃料.md"};function i(s,t,n,o,h,p){return d(),e("div",null,[...t[0]||(t[0]=[l(`<h1 id="绿电直连-2-0——从企业购电到物理直连" tabindex="-1">绿电直连 2.0——从企业购电到物理直连 <a class="header-anchor" href="#绿电直连-2-0——从企业购电到物理直连" aria-label="Permalink to &quot;绿电直连 2.0——从企业购电到物理直连&quot;">​</a></h1><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>绿电直连 2.0 是 2026 年正式启动的能源消费革命性变革。核心是：高载能企业（数据中心/电解铝/绿氢/绿氨/绿醇）与新能源电站通过专线&quot;物理直连&quot;，不再经过电网调度的统一调配。国家能源局已原则同意开展绿电直连示范，沈阳 50 万吨绿色醇油项目、内蒙古赤峰远景绿色氢氨项目、新疆库车绿氢项目等首批示范已在推进。绿电直连可降低用电成本 30%-50%，是工业脱碳的终极解决方案。</p><h2 id="什么是绿电直连-2-0" tabindex="-1">什么是绿电直连 2.0 <a class="header-anchor" href="#什么是绿电直连-2-0" aria-label="Permalink to &quot;什么是绿电直连 2.0&quot;">​</a></h2><p>传统绿电消费路径：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>新能源电站 → 电网 → 大电网调度 → 企业（经过多次转供）</span></span>
<span class="line"><span>企业购买的是&quot;绿色溢价&quot;而非&quot;绿色电力本身&quot;</span></span></code></pre></div><p>绿电直连 2.0 路径：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>新能源电站 ──专线──→ 高载能企业（物理直连，实时消纳）</span></span>
<span class="line"><span>                ↓ 余电</span></span>
<span class="line"><span>             电网（仅余电上网）</span></span>
<span class="line"><span>企业消费的是&quot;真正的绿色电力&quot;</span></span></code></pre></div><h3 id="核心区别" tabindex="-1">核心区别 <a class="header-anchor" href="#核心区别" aria-label="Permalink to &quot;核心区别&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>绿电直接交易 (1.0)</th><th>绿电直连 (2.0)</th></tr></thead><tbody><tr><td>物理路径</td><td>经电网调度后传输</td><td>专线直连，不经调度</td></tr><tr><td>消纳保障</td><td>双边交易合同</td><td>物理消纳，实时匹配</td></tr><tr><td>可靠性</td><td>电网保障</td><td>需自配储能/备电</td></tr><tr><td>适用场景</td><td>一般工商业</td><td>高载能企业（数据中心/电解铝/制氢）</td></tr><tr><td>成本</td><td>绿电溢价 + 过网费</td><td>免去过网费，成本低 30%-50%</td></tr></tbody></table><h2 id="政策进展" tabindex="-1">政策进展 <a class="header-anchor" href="#政策进展" aria-label="Permalink to &quot;政策进展&quot;">​</a></h2><ul><li><strong>国家能源局 2025 年</strong>：原则同意开展绿电直连示范</li><li><strong>2026 年</strong>：《电力法》修订研讨中，可能为绿电直连奠定法律基础</li><li><strong>正在推进的示范项目</strong>： <ul><li>沈阳 50 万吨级绿色醇油项目（总投资 320 亿元，2GW 风电直连）</li><li>内蒙古赤峰远景 152 万吨绿色氢氨项目（首期 32 万吨已投产，风电/光伏直连制氢）</li><li>新疆库车绿氢 2 万吨项目（光伏直连制氢，直供塔河炼化）</li></ul></li></ul><h2 id="绿色燃料产业链" tabindex="-1">绿色燃料产业链 <a class="header-anchor" href="#绿色燃料产业链" aria-label="Permalink to &quot;绿色燃料产业链&quot;">​</a></h2><p>绿电直连的最大应用场景不是数据中心，而是<strong>绿色燃料生产</strong>（绿氢→绿氨→绿醇→SAF）：</p><table tabindex="0"><thead><tr><th>产品</th><th>关键企业</th><th>技术路线</th><th>商业化进展</th></tr></thead><tbody><tr><td>绿氨</td><td>远景能源/国家电投</td><td>风光制氢→合成氨</td><td>赤峰 32 万吨已投产</td></tr><tr><td>绿醇</td><td>中国能建/金风科技</td><td>风光制氢→CO2 加氢→甲醇</td><td>沈阳 50 万吨项目推进中</td></tr><tr><td>绿色航煤 (SAF)</td><td>中石化/中石油</td><td>HEFA/ATJ 路线</td><td>2026 年国内首批量产，年产能 35 万吨</td></tr><tr><td>绿色甲醇 (船用)</td><td>马士基/中集/金风</td><td>生物质+绿氢</td><td>2026 年 6 月为马士基首艘集装箱船加注</td></tr></tbody></table><h3 id="saf-可持续航空燃料-特别关注" tabindex="-1">SAF（可持续航空燃料）特别关注 <a class="header-anchor" href="#saf-可持续航空燃料-特别关注" aria-label="Permalink to &quot;SAF（可持续航空燃料）特别关注&quot;">​</a></h3><ul><li><strong>2026 年国内量产元年</strong>：中石化镇海炼化 10 万吨/年、中石油等合计年产能 35 万吨</li><li><strong>国际需求</strong>：欧盟 ReFuelEU 要求 2025 年 SAF 掺混 2%，2030 年 6%，2050 年 70%</li><li><strong>中国政策</strong>：民航局 2025 年启动 SAF 试点应用</li><li><strong>技术路线</strong>：HEFA（油脂加氢）为主流，ATJ（醇喷合成）是远期方向</li><li><strong>产能瓶颈</strong>：2026 年全球 SAF 产能仅 300-400 万吨，远不能满足需求</li></ul><h2 id="经济性分析" tabindex="-1">经济性分析 <a class="header-anchor" href="#经济性分析" aria-label="Permalink to &quot;经济性分析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>无绿电直连</th><th>绿电直连</th><th>成本节省</th></tr></thead><tbody><tr><td>数据中心</td><td>0.50-0.80 元/kWh</td><td>0.20-0.30 元/kWh</td><td>50%+</td></tr><tr><td>绿氢制备</td><td>16-20 元/kg</td><td>10-14 元/kg</td><td>30%-40%</td></tr><tr><td>绿氨</td><td>6000-8000 元/吨</td><td>4000-5500 元/吨</td><td>30%+</td></tr><tr><td>绿醇</td><td>3500-4500 元/吨</td><td>2500-3500 元/吨</td><td>25%+</td></tr></tbody></table><h2 id="投资逻辑" tabindex="-1">投资逻辑 <a class="header-anchor" href="#投资逻辑" aria-label="Permalink to &quot;投资逻辑&quot;">​</a></h2><ol><li><strong>绿电直连是确定性趋势</strong>：政策已开放示范，工业脱碳需求迫切</li><li><strong>绿色燃料出口是核心驱动</strong>：欧盟 CBAM + 航运业脱碳推动绿氨/绿醇/SAF 需求</li><li><strong>绿电直连 2.0 项目 IRR 预计 8%-15%</strong>，优于传统新能源项目</li><li><strong>关注标的</strong>：中国能建、远景能源、金风科技、中石化</li></ol><h2 id="风险提示" tabindex="-1">风险提示 <a class="header-anchor" href="#风险提示" aria-label="Permalink to &quot;风险提示&quot;">​</a></h2><ol><li>绿电直连政策法律基础仍在完善，《电力法》修订尚未完成</li><li>绿色燃料绿色溢价仍高（30%-140%），碳价支撑不足</li><li>绿色甲醇/SAF 全球产能扩张速度可能超需求增长</li><li>欧盟对中国绿色燃料的补贴和认证门槛待观察</li><li>大规模制氢/制氨储运基础设施投资巨大</li></ol><hr><p><em>来源：国家能源局、发改委、中国能源报、中国石化报、经济观察网</em><em>更新：2026-06-16</em></p>`,25)])])}const b=a(r,[["render",i]]);export{u as __pageData,b as default};
